const SHEET_ID = '1YRrB3WC1vdddZrHSaHVns7NQ7p1tzaqBlhwRDgP9OKA';
const TZ = 'America/Mexico_City';

// ── Helpers ───────────────────────────────────────────────────────────────

function parseDateTime(isoString) {
  if (!isoString) return ['', ''];
  var d = new Date(isoString);
  return [
    Utilities.formatDate(d, TZ, 'dd/MM/yyyy'),
    Utilities.formatDate(d, TZ, 'HH:mm:ss')
  ];
}

function calcDuration(startIso, endIso) {
  if (!startIso || !endIso) return '';
  var diffMs = new Date(endIso) - new Date(startIso);
  if (diffMs < 0) return '';
  var totalSec = Math.floor(diffMs / 1000);
  var h = Math.floor(totalSec / 3600);
  var m = Math.floor((totalSec % 3600) / 60);
  var s = totalSec % 60;
  if (h > 0) return h + 'h ' + m + 'min ' + s + 's';
  if (m > 0) return m + 'min ' + s + 's';
  return s + 's';
}

function cellToNum(fechaVal, horaVal) {
  try {
    var fecha, hora;
    if (fechaVal instanceof Date) {
      fecha = Utilities.formatDate(fechaVal, TZ, 'dd/MM/yyyy');
    } else {
      fecha = String(fechaVal).trim();
    }
    if (horaVal instanceof Date) {
      hora = Utilities.formatDate(horaVal, TZ, 'HH:mm');
    } else if (typeof horaVal === 'number') {
      var totalMins = Math.round(horaVal * 24 * 60);
      hora = String(Math.floor(totalMins / 60)).padStart(2, '0') + ':' +
             String(totalMins % 60).padStart(2, '0');
    } else {
      hora = String(horaVal).trim();
      if (hora === '' || hora === '0') hora = '00:00';
    }
    var dp = fecha.split('/');
    var hp = hora.split(':');
    if (dp.length < 3) return null;
    return parseInt(
      dp[2] + dp[1].padStart(2,'0') + dp[0].padStart(2,'0') +
      (hp[0]||'00').padStart(2,'0') + (hp[1]||'00').padStart(2,'0')
    );
  } catch(e) { return null; }
}

function numToDisplay(n) {
  var s = String(n);
  return s.slice(6,8)+'/'+s.slice(4,6)+'/'+s.slice(0,4)+' '+s.slice(8,10)+':'+s.slice(10,12);
}

function jsonResponse(obj) {
  return ContentService.createTextOutput(JSON.stringify(obj))
    .setMimeType(ContentService.MimeType.JSON);
}

// ── Hoja Configuración ────────────────────────────────────────────────────

function initConfigSheet(ss) {
  var cfg = ss.getSheetByName('Configuración');
  if (!cfg) {
    cfg = ss.insertSheet('Configuración');
    cfg.appendRow(['Modulo','Fecha Inicio','Hora Inicio','Fecha Fin','Hora Fin','Activo']);
    var h = cfg.getRange(1,1,1,6);
    h.setBackground('#1a2a4a'); h.setFontColor('#ffffff'); h.setFontWeight('bold');
    cfg.setFrozenRows(1);
    cfg.setColumnWidth(1,280); cfg.setColumnWidth(2,120); cfg.setColumnWidth(3,100);
    cfg.setColumnWidth(4,120); cfg.setColumnWidth(5,100); cfg.setColumnWidth(6,80);
    var modulos = [
      'Módulo 1: Fundamentos Eléctricos Automotrices',
      'Módulo 2: Arquitectura Vehicular Moderna',
      'Módulo 3: Protocolo CAN y OBD2',
      'Módulo 4: Dispositivos de Rastreo',
      'Módulo 5: Paro de Motor',
      'Módulo 6: Estándares de Instalación'
    ];
    modulos.forEach(function(mod) {
      cfg.appendRow([mod,'01/01/2026','00:00','31/12/2026','23:59','SI']);
    });
    cfg.getRange(2,6,modulos.length,1).setHorizontalAlignment('center');
  }
  return cfg;
}

// ── Hoja Sesiones ─────────────────────────────────────────────────────────

// ── Hoja Alumnos ──────────────────────────────────────────────────────────

function initAlumnosSheet(ss) {
  var al = ss.getSheetByName('Alumnos');
  if (!al) {
    al = ss.insertSheet('Alumnos');
    al.appendRow(['Nombre del Tecnico']);
    var h = al.getRange(1, 1, 1, 1);
    h.setBackground('#1a2a4a'); h.setFontColor('#ffffff'); h.setFontWeight('bold');
    al.setFrozenRows(1);
    al.setColumnWidth(1, 260);
    al.getRange(1, 3).setValue('⚠️ Agrega aquí los nombres exactos de los técnicos autorizados (uno por fila)');
    al.getRange(1, 3).setFontColor('#c0392b').setFontWeight('bold');
    al.setColumnWidth(3, 440);
  }
  return al;
}

function normalizar(str) {
  return String(str).trim().toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}

function alumnoAutorizado(al, nombre) {
  var data = al.getDataRange().getValues();
  var nombreNorm = normalizar(nombre);
  for (var i = 1; i < data.length; i++) {
    if (normalizar(data[i][0]) === nombreNorm) return true;
  }
  return false;
}

// ── Hoja Sesiones ─────────────────────────────────────────────────────────

function initSesionesSheet(ss) {
  var ses = ss.getSheetByName('Sesiones');
  if (!ses) {
    ses = ss.insertSheet('Sesiones');
    ses.appendRow(['Nombre del Tecnico','Modulo','Fecha Inicio','Hora Inicio','Estado']);
    var h = ses.getRange(1,1,1,5);
    h.setBackground('#1a2a4a'); h.setFontColor('#ffffff'); h.setFontWeight('bold');
    ses.setFrozenRows(1);
    ses.setColumnWidth(1,180); ses.setColumnWidth(2,260);
    ses.setColumnWidth(3,120); ses.setColumnWidth(4,100); ses.setColumnWidth(5,130);
    // Nota para el instructor
    ses.getRange(1,7).setValue('⚠️ Para desbloquear un alumno: cambia su Estado a DESBLOQUEADO');
    ses.getRange(1,7).setFontColor('#c0392b').setFontWeight('bold');
    ses.setColumnWidth(7,380);
  }
  return ses;
}

function buscarSesion(ses, nombre, modulo) {
  var data = ses.getDataRange().getValues();
  for (var i = 1; i < data.length; i++) {
    if (String(data[i][0]).trim().toLowerCase() === nombre.trim().toLowerCase() &&
        String(data[i][1]).trim().toLowerCase() === modulo.trim().toLowerCase()) {
      return { fila: i + 1, estado: String(data[i][4]).trim().toUpperCase() };
    }
  }
  return null;
}

// ── Setup: inicializar todas las pestañas ─────────────────────────────────

function setup() {
  var ss = SpreadsheetApp.openById(SHEET_ID);
  initConfigSheet(ss);
  initAlumnosSheet(ss);
  initSesionesSheet(ss);
  Logger.log('✅ Todas las pestañas inicializadas correctamente.');
}

// ── doGet: disponibilidad + verificar sesión ──────────────────────────────

function doGet(e) {
  var modulo = e && e.parameter && e.parameter.modulo ? e.parameter.modulo : '';
  var action = e && e.parameter && e.parameter.action ? e.parameter.action : '';

  // Sin parámetros → inicializar pestañas y confirmar
  if (!modulo && !action) {
    try {
      var ss0 = SpreadsheetApp.openById(SHEET_ID);
      initConfigSheet(ss0);
      initAlumnosSheet(ss0);
      initSesionesSheet(ss0);
    } catch(e0) {}
    return ContentService.createTextOutput('Web app activa - Resultados Examenes Numaris')
      .setMimeType(ContentService.MimeType.TEXT);
  }

  // Verificar alumno autorizado + sesión previa
  if (action === 'verificar_sesion') {
    var nombre = e.parameter.nombre || '';
    try {
      var ss  = SpreadsheetApp.openById(SHEET_ID);
      var al  = initAlumnosSheet(ss);
      var ses = initSesionesSheet(ss);

      // 1. Verificar lista blanca
      var listaVacia = al.getLastRow() <= 1;
      if (!listaVacia && !alumnoAutorizado(al, nombre)) {
        return jsonResponse({ permitido: false, razon: 'no_autorizado',
          mensaje: 'El nombre "' + nombre + '" no está registrado como técnico autorizado. Verifica que lo escribiste exactamente como aparece en tu registro.' });
      }

      // 2. Verificar si ya inició
      var found = buscarSesion(ses, nombre, modulo);
      if (!found) return jsonResponse({ permitido: true });
      if (found.estado === 'DESBLOQUEADO') return jsonResponse({ permitido: true });
      if (found.estado === 'COMPLETADO')
        return jsonResponse({ permitido: false, razon: 'ya_enviado',
          mensaje: 'Ya enviaste este examen. Tu resultado fue registrado.' });
      return jsonResponse({ permitido: false, razon: 'ya_iniciado',
        mensaje: 'Ya iniciaste este examen desde otro dispositivo o navegador. Contacta al instructor si crees que es un error.' });
    } catch(err) {
      return jsonResponse({ permitido: true, razon: 'error' });
    }
  }

  // Verificar disponibilidad por fechas (llamada al cargar la página)
  if (!modulo) {
    return ContentService.createTextOutput('Web app activa - Resultados Examenes Numaris')
      .setMimeType(ContentService.MimeType.TEXT);
  }

  try {
    var ss  = SpreadsheetApp.openById(SHEET_ID);
    var cfg = initConfigSheet(ss);
    var rows = cfg.getDataRange().getValues();
    var nowNum = parseInt(Utilities.formatDate(new Date(), TZ, 'yyyyMMddHHmm'));

    for (var i = 1; i < rows.length; i++) {
      var row = rows[i];
      if (String(row[0]).trim().toLowerCase() !== modulo.trim().toLowerCase()) continue;
      var activo = String(row[5]).trim().toUpperCase();
      if (activo !== 'SI') return jsonResponse({ disponible: false, razon: 'desactivado',
        mensaje: 'Este examen ha sido desactivado por el instructor.' });
      var iniNum = cellToNum(row[1], row[2]);
      var finNum = cellToNum(row[3], row[4]);
      if (iniNum === null || finNum === null) return jsonResponse({ disponible: true, razon: 'sin_fechas' });
      if (nowNum < iniNum) return jsonResponse({ disponible: false, razon: 'aun_no',
        mensaje: 'El examen aún no está disponible.',
        fechaInicio: numToDisplay(iniNum), fechaFin: numToDisplay(finNum) });
      if (nowNum > finNum) return jsonResponse({ disponible: false, razon: 'cerrado',
        mensaje: 'El período de evaluación ha cerrado.',
        fechaInicio: numToDisplay(iniNum), fechaFin: numToDisplay(finNum) });
      return jsonResponse({ disponible: true, razon: 'ok',
      duracion: Number(row[7]) || 45,
        fechaInicio: numToDisplay(iniNum), fechaFin: numToDisplay(finNum) });
    }
    return jsonResponse({ disponible: true, razon: 'no_configurado' });
  } catch(err) {
    return jsonResponse({ disponible: true, razon: 'error', error: err.message });
  }
}

// ── doPost ────────────────────────────────────────────────────────────────

function doPost(e) {
  try {
    var data = JSON.parse(e.postData.contents);
    var ss = SpreadsheetApp.openById(SHEET_ID);
    initConfigSheet(ss);
    var ses = initSesionesSheet(ss);

    // Acción: registrar inicio de sesión
    if (data.action === 'registrar_inicio') {
      // Doble-check lista blanca al registrar
      var al2 = initAlumnosSheet(ss);
      var listaVacia2 = al2.getLastRow() <= 1;
      if (!listaVacia2 && !alumnoAutorizado(al2, data.nombre || '')) {
        return jsonResponse({ permitido: false, razon: 'no_autorizado' });
      }
      var found = buscarSesion(ses, data.nombre, data.modulo);
      if (found && found.estado !== 'DESBLOQUEADO') {
        // Ya existe y no está desbloqueado → rechazar
        return jsonResponse({ permitido: false,
          razon: found.estado === 'COMPLETADO' ? 'ya_enviado' : 'ya_iniciado' });
      }
      var startParts = parseDateTime(data.startTime);
      if (found && found.estado === 'DESBLOQUEADO') {
        // Actualizar fila existente a INICIADO
        ses.getRange(found.fila, 3).setValue(startParts[0]);
        ses.getRange(found.fila, 4).setValue(startParts[1]);
        ses.getRange(found.fila, 5).setValue('INICIADO');
      } else {
        ses.appendRow([data.nombre, data.modulo, startParts[0], startParts[1], 'INICIADO']);
      }
      return jsonResponse({ permitido: true });
    }

    // Acción: guardar resultado del examen
    var startParts = parseDateTime(data.startTime);
    var endParts   = parseDateTime(data.endTime);
    var duracion   = calcDuration(data.startTime, data.endTime);

    // Actualizar sesión a COMPLETADO
    var sesFound = buscarSesion(ses, data.nombre || '', data.modulo || '');
    if (sesFound) {
      ses.getRange(sesFound.fila, 5).setValue('COMPLETADO');
    }

    // Hoja Resultados
    var sheet = ss.getSheets()[0];
    if (sheet.getName() !== 'Resultados') sheet.setName('Resultados');
    if (sheet.getLastRow() === 0) {
      sheet.appendRow(['Fecha Inicio','Hora Inicio','Nombre del Tecnico','Modulo',
        'Puntaje Total','Maximo','Porcentaje','Resultado',
        'Sec A (Opcion Multiple)','Sec B (V/F)','Sec C (Casos)','Sec D (Orden)',
        'Fecha Termino','Hora Termino']);
      var h = sheet.getRange(1,1,1,14);
      h.setBackground('#1a2a4a'); h.setFontColor('#ffffff'); h.setFontWeight('bold');
      sheet.setFrozenRows(1);
    }
    sheet.appendRow([startParts[0], startParts[1], data.nombre||'Anonimo', data.modulo||'',
      data.puntaje||0, data.maximo||100, data.porcentaje||'0%', data.resultado||'',
      data.secA||'', data.secB||'', data.secC||'', data.secD||'',
      endParts[0], endParts[1]]);

    // Hoja Detalle
    var detalle = ss.getSheetByName('Detalle');
    if (!detalle) detalle = ss.insertSheet('Detalle');
    if (detalle.getLastRow() === 0) {
      detalle.appendRow(['Fecha Inicio','Hora Inicio','Nombre del Tecnico','Modulo','Resultado',
        'Seccion','Pregunta','Respuesta del Alumno','Respuesta Correcta',
        'Fecha Termino','Hora Termino','Tiempo Total']);
      var hd = detalle.getRange(1,1,1,12);
      hd.setBackground('#1a2a4a'); hd.setFontColor('#ffffff'); hd.setFontWeight('bold');
      detalle.setFrozenRows(1);
      detalle.setColumnWidth(1,110); detalle.setColumnWidth(2,90);
      detalle.setColumnWidth(3,160); detalle.setColumnWidth(4,200);
      detalle.setColumnWidth(6,80);  detalle.setColumnWidth(7,360);
      detalle.setColumnWidth(8,240); detalle.setColumnWidth(9,240);
      detalle.setColumnWidth(10,110); detalle.setColumnWidth(11,90);
      detalle.setColumnWidth(12,100);
    }
    (data.incorrectas||[]).forEach(function(q) {
      detalle.appendRow([startParts[0], startParts[1], data.nombre||'Anonimo',
        data.modulo||'', data.resultado||'', 'Sección '+(q.seccion||''),
        q.pregunta||'', q.respuesta||'—', q.respuesta_correcta||'—',
        endParts[0], endParts[1], duracion]);
    });

    return jsonResponse({ success: true, message: 'Resultado guardado' });
  } catch(err) {
    return jsonResponse({ success: false, error: err.message });
  }
}
